      font-size: 0.72rem;
      font-weight: 600;
      letter-spacing: 0.1em;
      text-transform: uppercase;
      color: var(--accent);
      background: rgba(240,62,27,0.08);
      border: 1px solid rgba(240,62,27,0.18);
      border-radius: 100px;
      padding: 0.25rem 0.85rem;
    }

