      font-size: 0.88rem;
      color: var(--muted);
      font-weight: 400;
    }

    .tracker-eta strong {
      color: var(--dark);
      font-weight: 600;
    }

    .tracker-title {
      font-family: 'Bebas Neue', sans-serif;
      font-size: 2rem;
      letter-spacing: 0.03em;
      margin: 0.7rem 0 1.8rem;
      line-height: 1;
    }

    .tracker-title span { color: var(--accent); }

    /* ── ROAD ── */
    .road-wrap {
      position: relative;
      padding: 0.5rem 0 1rem;
      margin-bottom: 1.8rem;
    }

    /* dots row */
    .road-dots {
      display: flex;
      align-items: center;
      justify-content: space-between;
      position: relative;
    }

    /* line behind dots */
    .road-line {
      position: absolute;
      top: 50%;
      left: 0; right: 0;
      height: 4px;
      background: var(--border);
      border-radius: 4px;
      transform: translateY(-50%);
      z-index: 0;
    }

    /* filled progress line */
    .road-progress {
      position: absolute;
      top: 50%;
      left: 0;
      height: 4px;
      background: linear-gradient(90deg, var(--accent), var(--accent2));
      border-radius: 4px;
      transform: translateY(-50%);
      z-index: 1;
      transition: width 0.6s ease;
      width: 0%;
    }

