      position: relative;
      z-index: 2;
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 0.55rem;
    }

    .milestone-dot {
      width: 18px; height: 18px;
      border-radius: 50%;
      border: 3px solid var(--border);
      background: var(--bg);
      transition: border-color 0.4s, background 0.4s, box-shadow 0.4s;
    }

    .milestone.done .milestone-dot {
      background: var(--accent);
      border-color: var(--accent);
      box-shadow: 0 0 0 4px rgba(240,62,27,0.15);
    }

    .milestone.active .milestone-dot {
      background: var(--surface);
      border-color: var(--accent);
      box-shadow: 0 0 0 4px rgba(240,62,27,0.15);
      animation: dotPulse 1.4s ease-in-out infinite;
    }

    @keyframes dotPulse {
      0%, 100% { box-shadow: 0 0 0 4px rgba(240,62,27,0.15); }
      50% { box-shadow: 0 0 0 8px rgba(240,62,27,0.06); }
    }

    .milestone-name {
      font-size: 0.7rem;
      font-weight: 500;
      color: var(--muted);
      text-align: center;
      max-width: 72px;
      line-height: 1.3;
      transition: color 0.4s;
      white-space: nowrap;
    }

    .milestone.done .milestone-name,
    .milestone.active .milestone-name {
      color: var(--dark);
    }

