      position: absolute;
      /* sits on top of the line */
      top: calc(50% - 26px);
      /* start slightly before first dot */
      left: 0;
      z-index: 3;
      pointer-events: none;
      transition: left 1s cubic-bezier(0.34, 1.2, 0.64, 1);
    }

    .rider {
      font-size: 1.9rem;
      line-height: 1;
      /* a tiny shadow so it floats over the line */
      filter: drop-shadow(0 3px 6px rgba(26,21,8,0.18));
      display: block;
      /* flip depending on direction — always faces right */
      transform: scaleX(1);
      animation: riderBob 0.55s ease-in-out infinite alternate;
    }

    @keyframes riderBob {
      from { transform: translateY(0px) scaleX(1); }
      to   { transform: translateY(-4px) scaleX(1); }
    }

    /* ── STATUS ROW ── */
    .status-row {
      display: flex;
      align-items: center;
      gap: 0.9rem;
      background: rgba(26,21,8,0.03);
      border: 1px solid var(--border);
      border-radius: 16px;
      padding: 1rem 1.3rem;
      margin-bottom: 1.2rem;
    }

    .status-icon {
      font-size: 1.8rem;
      flex-shrink: 0;
    }

    .status-text {
      flex: 1;
    }

    .status-title {
      font-weight: 600;
      font-size: 0.97rem;
      color: var(--dark);
      margin-bottom: 0.1rem;
    }

    .status-sub {
      font-size: 0.82rem;
      color: var(--muted);
    }

    .status-time {
      font-family: 'Bebas Neue', sans-serif;
      font-size: 1.6rem;
      color: var(--accent);
      letter-spacing: 0.04em;
      white-space: nowrap;
    }

