      background: var(--dark);
      color: #fff;
      border: none;
      border-radius: 100px;
      padding: 0.82rem;
      font-family: 'Outfit', sans-serif;
      font-size: 0.92rem;
      font-weight: 600;
      cursor: pointer;
      transition: background 0.2s, transform 0.15s;
      letter-spacing: 0.02em;
    }

    .sim-btn:hover { background: var(--accent); transform: translateY(-1px); }
    .sim-btn:active { transform: translateY(0); }
  </style>
</head>
<body>

  <div class="tracker-card">

    <div class="tracker-header">
      <span class="tracker-label">Live Tracking</span>
      <span class="tracker-eta">Arrives in <strong id="eta-text">22 mins</strong></span>
    </div>

    <div class="tracker-title">
      Your order is <span id="status-headline">on its way</span>!
    </div>

    <!-- ROAD -->
    <div class="road-wrap" id="road-wrap">
      <div class="road-line"></div>
      <div class="road-progress" id="progress-bar"></div>

      <div class="road-dots">
        <div class="milestone done" id="m0">
          <div class="milestone-dot"></div>
          <div class="milestone-name">Order<br>Placed</div>
        </div>
        <div class="milestone active" id="m1">
          <div class="milestone-dot"></div>
          <div class="milestone-name">Preparing</div>
        </div>
        <div class="milestone" id="m2">
          <div class="milestone-dot"></div>
          <div class="milestone-name">On the<br>Way</div>
        </div>
        <div class="milestone" id="m3">
          <div class="milestone-dot"></div>
          <div class="milestone-name">Delivered!</div>
        </div>
      </div>

      <!-- Rider emoji — positioned via JS -->
      <div class="rider-wrap" id="rider">
        <span class="rider">🛵</span>
      </div>
    </div>

    <!-- STATUS DETAIL -->
    <div class="status-row">
      <div class="status-icon" id="status-icon">👨‍🍳</div>
      <div class="status-text">
        <div class="status-title" id="status-title">Your chef is cooking your order</div>
        <div class="status-sub" id="status-sub">Estimated prep time: 10 mins</div>
      </div>
      <div class="status-time" id="eta-badge">22m</div>
    </div>

    <button class="sim-btn" id="sim-btn" onclick="nextStep()">▶ Simulate Next Step</button>

  </div>

  <script>
    // ─── DATA ───────────────────────────────────────────────
    const steps = [
      {
        milestoneIdx: 0,           // which dot is "active" (0-indexed)
        progress: 0,               // % fill of the progress bar
        headline: 'confirmed',
        icon: '✅',
        title: 'Order confirmed!',
        sub: 'The restaurant has accepted your order.',
        eta: '28m',
        etaText: '28 mins',
        btnLabel: '▶ Simulate Next Step',
      },
      {
        milestoneIdx: 1,
        progress: 33,
        headline: 'being prepared',
        icon: '👨‍🍳',
        title: 'Your chef is cooking your order',
        sub: 'Estimated prep time: 10 mins',
        eta: '22m',
        etaText: '22 mins',
        btnLabel: '▶ Simulate Next Step',
      },
      {
        milestoneIdx: 2,
        progress: 66,
        headline: 'on its way',
        icon: '🛵',
        title: 'Rider picked up your order',
        sub: 'Ravi is heading your way — approx 2 km away.',
        eta: '10m',
        etaText: '10 mins',
        btnLabel: '▶ Simulate Next Step',
      },
      {
        milestoneIdx: 3,
        progress: 100,
        headline: 'delivered 🎉',
        icon: '🎉',
        title: 'Order delivered!',
        sub: 'Enjoy your meal. Rate your experience below.',
        eta: '0m',
        etaText: 'Now',
        btnLabel: '✓ Done',
      },
    ];

    let currentStep = 1; // start at "preparing"
    applyStep(currentStep, true);

    // ─── APPLY STEP ─────────────────────────────────────────
    function applyStep(idx, instant) {
      const s = steps[idx];

      // update text
      document.getElementById('status-headline').textContent = s.headline;
      document.getElementById('status-icon').textContent     = s.icon;
      document.getElementById('status-title').textContent    = s.title;
      document.getElementById('status-sub').textContent      = s.sub;
      document.getElementById('eta-badge').textContent       = s.eta;
      document.getElementById('eta-text').textContent        = s.etaText;
      document.getElementById('sim-btn').textContent         = s.btnLabel;
      document.getElementById('sim-btn').disabled = (idx === steps.length - 1);

      // progress bar
      const bar = document.getElementById('progress-bar');
      if (instant) bar.style.transition = 'none';
      bar.style.width = s.progress + '%';
      if (instant) requestAnimationFrame(() => bar.style.transition = '');

      // milestones
      const milestones = document.querySelectorAll('.milestone');
      milestones.forEach((m, i) => {
        m.classList.remove('done', 'active');
        if (i < s.milestoneIdx) m.classList.add('done');
        if (i === s.milestoneIdx) m.classList.add('active');
      });

      // rider position
      positionRider(s.milestoneIdx, s.progress, instant);
    }

    // ─── RIDER POSITION ─────────────────────────────────────
    function positionRider(milestoneIdx, progressPct, instant) {
      const road = document.getElementById('road-wrap');
      const rider = document.getElementById('rider');
      const dots = document.querySelectorAll('.milestone');

      const roadW   = road.offsetWidth;
      const riderW  = rider.offsetWidth;

      // get the x-center of each dot relative to road-wrap
      const dotCenters = Array.from(dots).map(d => {
        const r = d.getBoundingClientRect();
        const rr = road.getBoundingClientRect();
        return r.left - rr.left + r.width / 2;
      });

      // lerp between dot centers based on progress pct
      const totalSpan = dotCenters[dotCenters.length - 1] - dotCenters[0];
      const targetX   = dotCenters[0] + (progressPct / 100) * totalSpan;

      // center the rider on targetX, offset up so it sits above the line
      const left = targetX - riderW / 2;

      if (instant) {
        rider.style.transition = 'none';
        rider.style.left = left + 'px';
        requestAnimationFrame(() => rider.style.transition = '');
      } else {
        rider.style.left = left + 'px';
      }
    }

    // ─── NEXT STEP ──────────────────────────────────────────
    function nextStep() {
      if (currentStep < steps.length - 1) {
        currentStep++;
        applyStep(currentStep, false);
      }
    }

    // recalc rider position on resize
    window.addEventListener('resize', () => {
      const s = steps[currentStep];
      positionRider(s.milestoneIdx, s.progress, true);
    });
  </script>

</body>
</html>

